#[test]
fn oversized_dead_letter_batch_overshoots_cap_instead_of_blocking() {
    use super::dead_letter::DeadLetterWriter;
    let dir = tmp_dir("f03_overshoot_perm");
    let mut dl = DeadLetterWriter::open(&dir).unwrap();
    // Cap far below the minimum sealed-segment framing (~60 bytes) so ANY
    // non-empty batch is "oversized" — blocking could never clear.
    let config = tight_dl_config(dir.clone(), 10);
    let metrics = noop_metrics();

    // Permanent error → the whole batch is dead-lettered.
    let sink = MockSink::with_responses([Err(MockError::Permanent)]);
    let payloads = vec![Payload::from(b"a-record".as_ref())];

    let result = block_on(commit_batch(&payloads, &sink, &config, &metrics, &mut dl));
    assert!(
        matches!(result, BatchResult::Ok),
        "a single batch larger than the cap must be written anyway (overshoot), not Blocked \
         (Blocked would livelock: even an empty dir can't hold it) (F03)"
    );
    assert_eq!(records_dead_lettered(&metrics), 1, "the oversized batch must be written");
    assert!(
        dl.total_bytes() > config.dead_letter_max_bytes,
        "the dir is intentionally over-cap after the one-time overshoot"
    );
    let dl_dir = dir.join("dead_letter");
    let n = std::fs::read_dir(&dl_dir).unwrap()
        .filter_map(|e| e.ok())
        .filter(|e| e.path().to_str().unwrap_or("").ends_with(".wab.sealed"))
        .count();
    assert_eq!(n, 1, "exactly one dead-letter segment written");
    std::fs::remove_dir_all(dir).ok();
}

#[test]
fn oversized_partial_dead_letter_overshoots_cap_instead_of_blocking() {
    use super::dead_letter::DeadLetterWriter;
    let dir = tmp_dir("f03_overshoot_partial");
    let mut dl = DeadLetterWriter::open(&dir).unwrap();
    let config = tight_dl_config(dir.clone(), 10);
    let metrics = noop_metrics();

    // Commit succeeds but reports one record permanently rejected; the rejected
    // sub-batch alone exceeds the cap.
    let sink = MockSink::with_responses([MockSink::ok_with_dead_letter(
        vec![Payload::from(b"ok".as_ref())],
        vec![Payload::from(b"rejected-record".as_ref())],
    )]);
    let payloads = vec![
        Payload::from(b"ok".as_ref()),
        Payload::from(b"rejected-record".as_ref()),
    ];

    let result = block_on(commit_batch(&payloads, &sink, &config, &metrics, &mut dl));
    assert!(
        matches!(result, BatchResult::Ok),
        "an oversized partial dead-letter must overshoot, not Blocked (F03)"
    );
    assert_eq!(records_dead_lettered(&metrics), 1);
    assert!(dl.total_bytes() > config.dead_letter_max_bytes);
    std::fs::remove_dir_all(dir).ok();
}

#[test]
fn replay_skips_already_confirmed_segment() {
    use crate::wab::format::{build_confirmed, confirmed_path_for};
    let dir = tmp_dir("replay_skip_confirmed");
    let shard_dir = shard_dir_path(&dir, 0);
    fs::create_dir_all(&shard_dir).unwrap();

    // seg 1: sealed AND confirmed (delivered on a prior run, segment not yet GC'd).
    let p1 = segment_path(&shard_dir, 1);
    let mut s1 = WabSegment::create(&p1, 0).unwrap();
    s1.write_record(b"already-delivered").unwrap();
    let sealed1 = s1.seal().unwrap();
    let confirmed1 = confirmed_path_for(&sealed1);
    fs::write(&confirmed1, build_confirmed(0, 1, 1)).unwrap();

    // seg 2: sealed, NOT confirmed (genuinely undrained).
    let p2 = segment_path(&shard_dir, 2);
    let mut s2 = WabSegment::create(&p2, 0).unwrap();
    s2.write_record(b"needs-delivery").unwrap();
    let sealed2 = s2.seal().unwrap();

    let (tx, rx) = crossbeam_channel::bounded::<PathBuf>(256);
    let metrics = Arc::new(crate::metrics::Metrics::new().0);
    replay_unconfirmed(&dir, 1, &tx, &metrics).unwrap();
    drop(tx);

    let queued: Vec<String> = rx.iter().map(|p| p.display().to_string()).collect();
    assert_eq!(queued.len(), 1, "only the unconfirmed segment may be replayed; got {queued:?}");
    assert!(
        queued[0].ends_with("seg_00000002.wab.sealed"),
        "the undrained segment must be the one queued, got {queued:?}"
    );
    // The confirmed segment + its sidecar are left untouched by replay (read-only skip).
    assert!(sealed1.exists(), "replay must not delete the confirmed segment");
    assert!(confirmed1.exists(), "replay must not delete the .confirmed sidecar");
    // Only the replayed segment's record is counted toward the replay metric.
    assert_eq!(metrics.recovery_records_replayed.get(), 1);
    assert!(sealed2.exists()); // queued, not yet drained
    fs::remove_dir_all(dir).ok();
}

#[test]
fn recovery_truncates_mid_payload_keeping_valid_prefix() {
    let dir = tmp_dir("crash_mid_payload");
    let path = make_segment(&dir, 0, &[b"record1", b"record2", b"record3"]);

    // Truncate 3 bytes into record3's 7-byte payload: len(4)+crc(4) of record3
    // are fully present, payload is short → read_exact(&mut payload) returns
    // UnexpectedEof (the mid-payload branch), distinct from the mid-CRC branch
    // the existing crash test exercises.
    let truncate_at = 24 + 15 + 15 + 4 + 4 + 3; // = 65
    fs::OpenOptions::new()
        .write(true)
        .open(&path)
        .unwrap()
        .set_len(truncate_at)
        .unwrap();

    let sealed = recover_segment(&path, &dir, &noop_metrics()).unwrap();

    let records: Vec<weir_core::Payload> = crate::wab::SegmentReader::open(&sealed)
        .unwrap()
        .collect::<Result<Vec<_>, _>>()
        .unwrap();
    assert_eq!(
        records.len(),
        2,
        "a payload torn mid-bytes must truncate to the last whole record (rec2)"
    );
    assert_eq!(records[0], b"record1" as &[u8]);
    assert_eq!(records[1], b"record2" as &[u8]);
    assert!(!path.exists());
    assert!(sealed.to_str().unwrap().ends_with(".wab.sealed"));

    fs::remove_dir_all(dir).ok();
}

#[test]
fn recover_open_segments_isolates_a_corrupt_segment_from_healthy_siblings() {
    use crate::wab::segment::{WabSegment, segment_path, sealed_path_for};
    let wab_dir = tmp_dir("recover_isolate_corrupt");
    let shard_dir = wab_dir.join("shard_00");
    fs::create_dir_all(&shard_dir).unwrap();

    // Segment 1: valid then magic-corrupted → recover_segment quarantines + Errs.
    let corrupt = segment_path(&shard_dir, 1);
    WabSegment::create(&corrupt, 0).unwrap().write_record(b"healthy-1").unwrap();
    {
        let mut f = fs::OpenOptions::new().write(true).open(&corrupt).unwrap();
        f.write_all(b"XXXX").unwrap();
    }

    // Segment 2: healthy, left active — must still be sealed.
    let healthy = segment_path(&shard_dir, 2);
    WabSegment::create(&healthy, 0).unwrap().write_record(b"healthy-2").unwrap();

    let metrics = noop_metrics();
    // The corrupt segment must NOT abort the whole recovery.
    recover_open_segments(&wab_dir, &metrics).unwrap();

    // Healthy sibling sealed and readable.
    let healthy_sealed = sealed_path_for(&healthy);
    assert!(healthy_sealed.exists(), "healthy sibling must be sealed despite corrupt neighbour");
    let recovered: Vec<weir_core::Payload> = crate::wab::SegmentReader::open(&healthy_sealed)
        .unwrap()
        .collect::<Result<Vec<_>, _>>()
        .unwrap();
    assert_eq!(recovered.len(), 1);
    assert_eq!(recovered[0], b"healthy-2" as &[u8]);

    // Corrupt segment quarantined, not left in the shard dir.
    assert!(!corrupt.exists(), "corrupt segment should be moved to quarantine");
    assert!(wab_dir.join("quarantine").join("shard_00__seg_00000001.wab").exists());
    assert_eq!(metrics.recovery_segments_quarantined.get(), 1);

    fs::remove_dir_all(wab_dir).ok();
}

#[test]
fn tls_handshake_timeout_drops_stalled_tcp_client() {
    use std::net::TcpStream;
    let fx = TlsFixture::generate("hs_timeout");
    // Harness must allow a short handshake timeout; if not configurable, use the
    // default and widen the time bound accordingly.
    let srv = weir_server!("tls_hs_timeout").tls(&fx).handshake_timeout_secs(1).start();
    let addr = srv.tcp_addr();

    // Raw TCP connection that completes the TCP handshake then sends no TLS bytes.
    let mut raw = TcpStream::connect(addr).expect("tcp connect");
    raw.set_read_timeout(Some(Duration::from_secs(5))).unwrap();
    let t0 = std::time::Instant::now();

    // A legitimate mTLS client must still be served — proves the stalled
    // connection did not wedge the accept loop or exhaust the permit pool.
    let cfg = client_config_with_cert(&fx.ca_cert_path, &fx.client_cert_path, &fx.client_key_path);
    let mut good = tls_connect(addr, cfg).expect("valid client handshake");
    assert_eq!(push_one(&mut good, b"hello").unwrap(), MessageType::Ack);

    // The stalled raw socket is dropped by the server around handshake_timeout:
    // read() returns Ok(0) (EOF) once the server times out the handshake.
    let mut buf = [0u8; 1];
    let n = raw.read(&mut buf).unwrap_or(0);
    assert_eq!(n, 0, "server must close the stalled handshake connection");
    assert!(t0.elapsed() < Duration::from_secs(5),
        "stalled handshake must be dropped well within the read deadline");

    // If a metrics scrape helper is available, assert the timeout label fired:
    // let m = srv.scrape_metrics();
    // assert!(m.contains("weir_tls_handshake_failures") && m.contains("timeout"));

    srv.shutdown();
}

#[cfg(any(feature = "http-sink", feature = "clickhouse-sink"))]
#[tokio::test]
async fn read_body_capped_bounds_oversized_body() {
    use tokio::io::{AsyncReadExt, AsyncWriteExt};
    use tokio::net::TcpListener;
    // Server: answers any request with a 1000-byte body.
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    tokio::spawn(async move {
        loop {
            let Ok((mut sock, _)) = listener.accept().await else { return };
            tokio::spawn(async move {
                let mut tmp = [0u8; 1024];
                // read until end of header block
                let mut buf = Vec::new();
                loop {
                    match sock.read(&mut tmp).await {
                        Ok(0) | Err(_) => return,
                        Ok(n) => {
                            buf.extend_from_slice(&tmp[..n]);
                            if buf.windows(4).any(|w| w == b"\r\n\r\n") { break; }
                        }
                    }
                }
                let body = vec![b'Z'; 1000];
                let head = format!("HTTP/1.1 200 OK\r\nContent-Length: {}\r\n\r\n", body.len());
                let _ = sock.write_all(head.as_bytes()).await;
                let _ = sock.write_all(&body).await;
                let _ = sock.shutdown().await;
            });
        }
    });
    let url = format!("http://{addr}/");
    let client = reqwest::Client::new();
    // cap < body: must stop at the cap.
    let resp = client.get(&url).send().await.unwrap();
    let bytes = read_body_capped(resp, 100).await;
    assert_eq!(bytes.len(), 100, "cap not enforced: {}", bytes.len());
    // cap > body: must return the whole body (end-of-body branch).
    let resp = client.get(&url).send().await.unwrap();
    let bytes = read_body_capped(resp, 4096).await;
    assert_eq!(bytes.len(), 1000);
}

#[test]
fn empty_log_level_falls_back_to_info_not_silent() {
    // (1) An empty value in the winning layer resolves to "info" rather than
    // an empty string (which main's EnvFilter::try_new("") would turn into a
    // filter that disables ALL logging — F58).
    let dir = tmp_dir("loglevel_empty");
    let c = Config::from_layers(
        PartialConfig::empty(),
        PartialConfig::empty(),
        PartialConfig {
            wab_dir: Some(dir.clone()),
            log_level: Some(String::new()),
            ..PartialConfig::empty()
        },
    )
    .unwrap();
    assert_eq!(c.log_level, "info", "empty log_level must fall back to info");
    fs::remove_dir_all(&dir).ok();

    // (2) Whitespace-only is also treated as unset (proves .trim(), not just is_empty()).
    let dir = tmp_dir("loglevel_ws");
    let c = Config::from_layers(
        PartialConfig::empty(),
        PartialConfig::empty(),
        PartialConfig {
            wab_dir: Some(dir.clone()),
            log_level: Some("   ".to_string()),
            ..PartialConfig::empty()
        },
    )
    .unwrap();
    assert_eq!(c.log_level, "info", "whitespace-only log_level must fall back to info");
    fs::remove_dir_all(&dir).ok();

    // (3) Precedence: an empty value in a HIGHER layer wins the merge and then
    // falls back to "info" — it must NOT silently inherit the lower layer's
    // "debug". (env beats file in cli.or(env).or(file).)
    let dir = tmp_dir("loglevel_empty_shadows");
    let c = Config::from_layers(
        PartialConfig::empty(),
        PartialConfig {
            wab_dir: Some(dir.clone()),
            log_level: Some(String::new()),
            ..PartialConfig::empty()
        },
        PartialConfig {
            wab_dir: Some(dir.clone()),
            log_level: Some("debug".to_string()),
            ..PartialConfig::empty()
        },
    )
    .unwrap();
    assert_eq!(
        c.log_level, "info",
        "empty env log_level must resolve to info, not inherit file's debug"
    );
    fs::remove_dir_all(&dir).ok();
}

/// Invariant (c) end to end: a SIGKILL'd-then-restarted daemon must not merely
/// re-queue recovered segments — it must deliver their records to the sink and
/// confirm+delete the segments. Closes the gap between
/// recovery_records_replayed (queue step) and actual delivery.
#[test]
fn acked_records_delivered_to_sink_and_confirmed_after_crash_restart() {
    const N: u32 = 25;
    let mut srv = weir_server!("crash_to_sink").shard_count(1).start();
    let mut client = srv.client();
    for i in 0..N {
        client
            .push(format!("deliver-{i:05}").as_bytes(), Durability::Sync)
            .unwrap();
    }
    drop(client);

    srv.kill_ungracefully();
    srv.restart_in_place();

    // Poll until the recovered segment is delivered (NoopSink commits instantly,
    // but replay + drain are async after restart).
    let mut committed = 0u64;
    let deadline = Instant::now() + Duration::from_secs(3);
    while Instant::now() < deadline {
        let body = srv.scrape_metrics();
        committed = parse_metric(
            &body,
            "weir_sink_commit_records_total{outcome=\"committed\"}",
        );
        if committed >= u64::from(N) {
            break;
        }
        thread::sleep(Duration::from_millis(50));
    }
    assert!(
        committed >= u64::from(N),
        "recovered records must be DELIVERED to the sink post-restart, not just \
         re-queued: committed={committed}, expected >= {N}"
    );
    // And the recovered segment must be confirmed+deleted, leaving none stranded.
    let leftover_sealed = count_wab_files(&srv.wab_dir, ".wab.sealed");
    assert_eq!(
        leftover_sealed, 0,
        "every recovered sealed segment must be confirmed+deleted after delivery, \
         found {leftover_sealed} undrained"
    );
}

#[test]
fn segment_reader_rejects_oversized_record_len_before_allocation() {
    use crate::wab::segment::{WabSegment, segment_path};
    let dir = tmp_dir("rd_oversized_len");
    let path = segment_path(&dir, 1);
    {
        let mut seg = WabSegment::create(&path, 0).unwrap();
        seg.write_record(b"keep-me").unwrap();
    } // drop flushes the active segment to disk

    // Splice an oversized record-length field where the next record's length
    // prefix would begin. SegmentReader must reject it before allocating.
    let oversized = (MAX_PAYLOAD_HARD_CAP as u32 + 1).to_le_bytes();
    {
        use std::io::Write;
        let mut f = fs::OpenOptions::new().append(true).open(&path).unwrap();
        f.write_all(&oversized).unwrap();
        f.flush().unwrap();
    }

    let mut reader = SegmentReader::open(&path).unwrap();
    // First record reads cleanly.
    let first = reader.next().expect("a record").expect("valid record");
    assert_eq!(first, b"keep-me" as &[u8]);
    // Oversized length field is rejected with InvalidData before allocation.
    let err = reader
        .next()
        .expect("an item")
        .expect_err("over-cap length must be an Err, never a giant allocation");
    assert_eq!(err.kind(), std::io::ErrorKind::InvalidData, "{err}");
    assert!(
        err.to_string().contains("exceeds MAX_PAYLOAD_HARD_CAP"),
        "error must name the cap: {err}"
    );
    // Reader is done after the error: no further yields, no re-read loop.
    assert!(
        reader.next().is_none(),
        "reader must stop after the cap error (done=true)"
    );
    fs::remove_dir_all(dir).ok();
}

#[cfg(any(feature = "http-sink", feature = "clickhouse-sink"))]
#[tokio::test]
async fn read_body_capped_stops_at_cap_on_oversized_body() {
    use tokio::io::{AsyncReadExt, AsyncWriteExt};
    use tokio::net::TcpListener;

    // Mock server: send a 1 MiB body — far past any cap we test with.
    const BODY: usize = 1024 * 1024;
    let listener = TcpListener::bind("127.0.0.1:0").await.unwrap();
    let addr = listener.local_addr().unwrap();
    let url = format!("http://{addr}/");
    tokio::spawn(async move {
        loop {
            let Ok((mut sock, _)) = listener.accept().await else { return };
            tokio::spawn(async move {
                // Drain the request header block.
                let mut buf = Vec::new();
                let mut tmp = [0u8; 1024];
                loop {
                    match sock.read(&mut tmp).await {
                        Ok(0) | Err(_) => return,
                        Ok(n) => {
                            buf.extend_from_slice(&tmp[..n]);
                            if buf.windows(4).any(|w| w == b"\r\n\r\n") { break; }
                        }
                    }
                }
                let header = format!("HTTP/1.1 200 OK\r\nContent-Length: {BODY}\r\n\r\n");
                let _ = sock.write_all(header.as_bytes()).await;
                let _ = sock.write_all(&vec![0x41u8; BODY]).await;
                let _ = sock.shutdown().await;
            });
        }
    });

    let client = reqwest::Client::new();

    // Tiny cap: the body exceeds it inside the first chunk → mid-chunk break.
    let resp = client.get(&url).send().await.unwrap();
    let body = tokio::time::timeout(
        std::time::Duration::from_secs(5),
        super::read_body_capped(resp, 64),
    )
    .await
    .expect("read_body_capped must return promptly, not drain 1 MiB");
    assert_eq!(body.len(), 64, "must buffer exactly the cap, not the whole body");
    assert!(body.iter().all(|&b| b == 0x41), "must be real body bytes");

    // Production cap: still bounded at exactly RESPONSE_BODY_CAP.
    let resp = client.get(&url).send().await.unwrap();
    let body = super::read_body_capped(resp, super::RESPONSE_BODY_CAP).await;
    assert_eq!(
        body.len(),
        super::RESPONSE_BODY_CAP,
        "must cap at RESPONSE_BODY_CAP regardless of downstream body size"
    );
}

// add to the #[cfg(test)] mod in crates/weir-server/src/config/mod.rs
#[cfg(feature = "tls")]
#[test]
fn tcp_bind_rejects_relative_or_traversing_tls_paths() {
    let dir = tmp_dir("tls_path_fmt");
    let abs_ok = dir.join("ok.pem");
    fs::write(&abs_ok, b"x").unwrap();
    let build = |cert: PathBuf, key: PathBuf, ca: PathBuf| {
        let mut cli = PartialConfig::empty();
        cli.tcp_bind = Some("127.0.0.1:7100".to_string());
        cli.tls_cert_path = Some(cert);
        cli.tls_key_path = Some(key);
        cli.tls_client_ca_path = Some(ca);
        Config::from_layers(
            cli,
            PartialConfig::empty(),
            PartialConfig { wab_dir: Some(dir.clone()), ..PartialConfig::empty() },
        )
    };

    // Relative cert path → rejected, names the field, says 'absolute'.
    let err = build(PathBuf::from("relative/cert.pem"), abs_ok.clone(), abs_ok.clone())
        .expect_err("a relative tls_cert_path must be rejected (S42)");
    assert!(matches!(err, ConfigError::PathInvalid { .. }), "{err}");
    assert!(err.to_string().contains("tls_cert_path"), "{err}");
    assert!(err.to_string().contains("absolute"), "{err}");

    // '..' traversal in the key path → rejected, names the field, mentions '..'.
    let err = build(abs_ok.clone(), PathBuf::from("/etc/weir/../../etc/shadow"), abs_ok.clone())
        .expect_err("a '..' tls_key_path must be rejected (S42)");
    assert!(matches!(err, ConfigError::PathInvalid { .. }), "{err}");
    assert!(err.to_string().contains("tls_key_path"), "{err}");
    assert!(err.to_string().contains(".."), "{err}");

    // CA path relative → rejected, names the field.
    let err = build(abs_ok.clone(), abs_ok.clone(), PathBuf::from("certs/ca.pem"))
        .expect_err("a relative tls_client_ca_path must be rejected (S42)");
    assert!(err.to_string().contains("tls_client_ca_path"), "{err}");

    fs::remove_dir_all(dir).ok();
}

/// G10: a RESUMED segment (skip > 0) that then hits a read error must still
/// quarantine — the read_failed early-return fires before the
/// debug_assert_eq!(durable_through, read_index), so a resume into a
/// now-corrupt segment never panics in debug and never confirm+deletes the
/// unread tail. F05's resume test (retry_resumes_past_already_processed_sub_batches)
/// only covers the clean-resume case.
#[test]
fn resumed_segment_with_read_error_quarantines_not_panics() {
    use super::dead_letter::DeadLetterWriter;
    let dir = tmp_dir("g10_resume_corrupt");
    let sealed = make_sealed_segment(&dir, 0, &[b"r1", b"r2", b"r3"]);
    // Corrupt record 2's payload so the reader yields r1, then errors at r2.
    // Layout: 24-byte header + record1 [4 len + 4 crc + 2 payload] = 34;
    // record2 payload begins at byte 42 (same offset used by
    // mid_segment_read_error_quarantines_not_deletes).
    let mut bytes = std::fs::read(&sealed).unwrap();
    bytes[42] ^= 0xff;
    std::fs::write(&sealed, &bytes).unwrap();

    let mut dl = DeadLetterWriter::open(&dir).unwrap();
    let sink = MockSink::with_responses([]); // commits whatever prefix it is given
    let metrics = noop_metrics();
    let config = fast_config(dir.clone());

    // Resume as if record 1 was already durably processed on a prior attempt.
    let result = block_on(process_segment(
        &sealed, &sink, &config, &metrics, &mut dl, /*skip=*/ 1,
    ));
    assert!(
        matches!(result, ProcessResult::Quarantined),
        "a resumed segment that hits a read error must quarantine, not confirm or panic"
    );
    assert!(!sealed.exists(), "the corrupt segment must be moved to quarantine");
    let q = dir.join("quarantine");
    assert!(
        q.is_dir() && std::fs::read_dir(&q).unwrap().count() == 1,
        "the segment must be preserved in quarantine for manual recovery"
    );
    assert_eq!(
        records_dead_lettered(&metrics), 0,
        "the skipped prefix must NOT be re-dead-lettered, and the tail is quarantined"
    );
    assert_eq!(
        records_committed(&metrics), 0,
        "nothing after the skip was readable, so nothing is committed"
    );
    std::fs::remove_dir_all(dir).ok();
}

#[tokio::test]
async fn http_permanent_status_truncates_large_body_excerpt() {
    // A hostile/verbose 4xx body must not land unbounded in the dead-letter
    // reason. The excerpt is cut at 256 bytes (http.rs:223).
    let body = "A".repeat(4096);
    let resp = format!(
        "HTTP/1.1 400 Bad Request\r\nContent-Length: {}\r\n\r\n{}",
        body.len(),
        body
    );
    // spawn_mock_server takes Vec<&'static str>; leak the owned response so it
    // satisfies the 'static bound (test-only, fine).
    let resp: &'static str = Box::leak(resp.into_boxed_str());
    let (url, _counter) = spawn_mock_server(vec![resp]).await;
    let sink = HttpSink::new(cfg(&url)).unwrap();
    let result = sink.commit(vec![p(b"x")]).await.unwrap();
    assert!(result.committed.is_empty());
    assert_eq!(result.dead_lettered.len(), 1);
    let reason = &result.dead_lettered[0].1;
    assert!(reason.contains("400"), "reason: {reason}");
    // The full 4096-byte run must NOT survive into the reason.
    assert!(
        !reason.contains(&"A".repeat(300)),
        "body excerpt was not truncated: {} bytes",
        reason.len()
    );
    // Prefix (~22 chars) + <=256 excerpt chars.
    assert!(reason.len() < 400, "reason too long: {} bytes", reason.len());
}

#[test]
fn percent_decode_assembles_multibyte_utf8() {
    // Consecutive %XX escapes must be accumulated as BYTES, then decoded as
    // UTF-8 — not decoded one Latin-1 char at a time (F34 credential path).
    assert_eq!(percent_decode("caf%C3%A9"), "café");
    assert_eq!(percent_decode("%E2%82%AC"), "\u{20AC}"); // €, 3-byte
    assert_eq!(percent_decode("a%C3%A9b"), "aéb");
}

#[test]
fn percent_decode_invalid_utf8_is_lossy_not_panic() {
    // A %XX that yields invalid UTF-8 must go through from_utf8_lossy:
    // no panic, replacement char rather than a crash on the commit path.
    let out = percent_decode("%FF");
    assert_eq!(out, "\u{FFFD}");
}

