    // A host:port form (the port belongs in metrics_port) is also not a bare IP.
    let dir = tmp_dir("metrics_bind_hostport");
    let err = Config::from_layers(
        PartialConfig::empty(),
        PartialConfig::empty(),
        PartialConfig {
            wab_dir: Some(dir.clone()),
            metrics_bind: Some("127.0.0.1:9185".to_string()),
            ..PartialConfig::empty()
        },
    )
    .unwrap_err();
    assert!(err.to_string().contains("metrics_bind"), "{err}");
    fs::remove_dir_all(&dir).ok();

    // (2) A valid address parses through; unset defaults to localhost.
    let dir = tmp_dir("metrics_bind_ok");
    let c = Config::from_layers(
        PartialConfig::empty(),
        PartialConfig::empty(),
        PartialConfig {
            wab_dir: Some(dir.clone()),
