#[cfg(test)]
mod tests {
    use super::*;
    use crate::config::ConfigError;

    // Env vars are process-global; this test owns uniquely-named keys and
    // cleans them up, and must run alone if the suite ever parallelises env use.
    #[test]
    fn env_bool_accepts_lenient_spellings_and_env_parse_wraps_errors() {
        // ── env_bool: lenient spellings (F57) ──
        // SAFETY: single-threaded test; keys are unique to this test.
        unsafe { std::env::set_var("WEIR_PEER_UID_CHECK", "1"); }
        assert_eq!(env_bool("WEIR_PEER_UID_CHECK").unwrap(), Some(true));
        unsafe { std::env::set_var("WEIR_PEER_UID_CHECK", "off"); }
        assert_eq!(env_bool("WEIR_PEER_UID_CHECK").unwrap(), Some(false));
        unsafe { std::env::set_var("WEIR_PEER_UID_CHECK", "TRUE"); }
        assert_eq!(env_bool("WEIR_PEER_UID_CHECK").unwrap(), Some(true),
            "env bools must go through lenient parse_bool, not bool::from_str (F57)");
        unsafe { std::env::remove_var("WEIR_PEER_UID_CHECK"); }
        assert_eq!(env_bool("WEIR_PEER_UID_CHECK").unwrap(), None,
            "an unset bool env var is None, not an error");

        // ── env_parse: error wrapping names the field ──
        unsafe { std::env::set_var("WEIR_SHARD_COUNT", "not-a-number"); }
        let err = env_parse::<u32>("WEIR_SHARD_COUNT").unwrap_err();
        match err {
            ConfigError::ParseError { field, .. } =>
                assert_eq!(field, "WEIR_SHARD_COUNT"),
            other => panic!("expected ParseError naming the field, got {other:?}"),
        }
        unsafe { std::env::remove_var("WEIR_SHARD_COUNT"); }
        assert_eq!(env_parse::<u32>("WEIR_SHARD_COUNT").unwrap(), None);
    }
}

// add to the #[cfg(test)] mod in crates/weir-server/src/queue.rs
#[test]
fn try_push_returns_unit_back_when_full_then_ok_when_drained() {
    let (tx, rx) = new_with_capacity::<u32>(1, 1);
    let recv = rx.get(0);

    assert!(tx.try_push(0, 1).is_ok(), "fast path succeeds with capacity");
    // Partition full: the unit must come back unchanged for the push_timeout fallback.
    assert_eq!(tx.try_push(0, 2), Err(2),
        "a full partition must hand the unit back, not drop it");

    assert_eq!(recv.recv().unwrap(), 1);
    assert!(tx.try_push(0, 3).is_ok(), "capacity restored after a drain");
}

#[test]
fn try_push_returns_unit_back_when_disconnected() {
    let (tx, rx) = new_with_capacity::<u32>(1, 1);
    drop(rx); // every receiver gone
    assert_eq!(tx.try_push(0, 99), Err(99),
        "a disconnected partition must hand the unit back (Disconnected -> Err)");
}

